// ── Helpers — JSON ────────────────────────────────────────────────────────────

static QJsonObject nodeToJson(const ConstrutorStore::Node& node)
{
    QJsonObject o;
    o.insert(QStringLiteral("id"),   node.id);
    o.insert(QStringLiteral("name"), node.name);
    o.insert(QStringLiteral("type"), node.type == ConstrutorStore::NodeType::Rule
                                         ? QStringLiteral("rule")
                                         : QStringLiteral("section"));
    if (!node.content.isEmpty())
        o.insert(QStringLiteral("content"), node.content);
    o.insert(QStringLiteral("updatedAt"), node.updatedAt);
    if (!node.children.isEmpty()) {
        QJsonArray children;
        for (const auto& c : node.children)
            children.append(nodeToJson(c));
        o.insert(QStringLiteral("children"), children);
    }
    return o;
}

static ConstrutorStore::Node nodeFromJson(const QJsonObject& o)
{
    ConstrutorStore::Node node;
    node.id      = o.value(QStringLiteral("id")).toString();
    node.name    = o.value(QStringLiteral("name")).toString();
    node.type    = o.value(QStringLiteral("type")).toString() == QLatin1String("rule")
                       ? ConstrutorStore::NodeType::Rule
                       : ConstrutorStore::NodeType::Section;
    node.content = o.value(QStringLiteral("content")).toString();
    node.updatedAt = o.value(QStringLiteral("updatedAt")).toVariant().toLongLong();
    for (const auto& v : o.value(QStringLiteral("children")).toArray())
        node.children.append(nodeFromJson(v.toObject()));
    return node;
}

static QJsonObject mentionToJson(const ConstrutorStore::Mention& m)
{
    QJsonObject o;
    o.insert(QStringLiteral("id"),   m.id);
    o.insert(QStringLiteral("text"), m.text);
    if (!m.nodeId.isEmpty())       o.insert(QStringLiteral("nodeId"), m.nodeId);
    if (!m.sourceType.isEmpty())   o.insert(QStringLiteral("sourceType"), m.sourceType);
    if (!m.sourceLabel.isEmpty()) o.insert(QStringLiteral("sourceLabel"), m.sourceLabel);
    if (!m.chapterId.isEmpty())    o.insert(QStringLiteral("chapterId"), m.chapterId);
    if (m.sceneIndex >= 0)         o.insert(QStringLiteral("sceneIndex"), m.sceneIndex);
    if (!m.manuscriptId.isEmpty()) o.insert(QStringLiteral("manuscriptId"), m.manuscriptId);
    if (!m.itemId.isEmpty())       o.insert(QStringLiteral("itemId"), m.itemId);
    o.insert(QStringLiteral("createdAt"), m.createdAt);
    return o;
}

static ConstrutorStore::Mention mentionFromJson(const QJsonObject& o)
{
    ConstrutorStore::Mention m;
    m.id           = o.value(QStringLiteral("id")).toString();
    m.text         = o.value(QStringLiteral("text")).toString();
    m.nodeId       = o.value(QStringLiteral("nodeId")).toString();
    m.sourceType   = o.value(QStringLiteral("sourceType")).toString();
    m.sourceLabel  = o.value(QStringLiteral("sourceLabel")).toString();
    m.chapterId    = o.value(QStringLiteral("chapterId")).toString();
    m.sceneIndex   = o.value(QStringLiteral("sceneIndex")).toInt(-1);
    m.manuscriptId = o.value(QStringLiteral("manuscriptId")).toString();
    m.itemId       = o.value(QStringLiteral("itemId")).toString();
    m.createdAt    = qint64(o.value(QStringLiteral("createdAt")).toDouble());
    return m;
}

// ── ConstrutorStore ───────────────────────────────────────────────────────────

ConstrutorStore::ConstrutorStore(QObject* parent)
    : QObject(parent)
{
}

void ConstrutorStore::setProjectRoot(const QString& root)
{
    if (m_root == root) return;
    m_root = root;
    m_systems.clear();
}

QString ConstrutorStore::sidecarPath() const
{
    if (m_root.isEmpty()) return {};
    return QDir::cleanPath(m_root + QStringLiteral("/construtor.json"));
}

bool ConstrutorStore::load()
{
    m_systems.clear();
    const QString path = sidecarPath();
    if (path.isEmpty()) return false;
    QFile f(path);
    if (!f.exists()) return true;
    if (!f.open(QIODevice::ReadOnly)) return false;
    const QByteArray data = f.readAll();
    f.close();

    QJsonParseError err;
    const QJsonDocument doc = QJsonDocument::fromJson(data, &err);
    if (err.error != QJsonParseError::NoError || !doc.isObject()) return false;

    for (const auto& v : doc.object().value(QStringLiteral("systems")).toArray()) {
        const QJsonObject o = v.toObject();
        System sys;
        sys.id          = o.value(QStringLiteral("id")).toString();
        sys.name        = o.value(QStringLiteral("name")).toString();
        sys.categoryId  = o.value(QStringLiteral("categoryId")).toString();
        sys.sliderIndex = o.value(QStringLiteral("sliderIndex")).toInt(0);
        sys.createdAt   = o.value(QStringLiteral("createdAt")).toVariant().toLongLong();
        sys.updatedAt   = o.value(QStringLiteral("updatedAt")).toVariant().toLongLong();
        sys.content     = o.value(QStringLiteral("content")).toString();
        for (const auto& nv : o.value(QStringLiteral("nodes")).toArray())
            sys.nodes.append(nodeFromJson(nv.toObject()));
        for (const auto& mv : o.value(QStringLiteral("mentions")).toArray())
            sys.mentions.append(mentionFromJson(mv.toObject()));
        if (!sys.id.isEmpty())
            m_systems.append(std::move(sys));
    }
    return true;
}

bool ConstrutorStore::save() const
{
    const QString path = sidecarPath();
    if (path.isEmpty()) return false;

    QJsonArray systems;
    for (const System& sys : m_systems) {
        QJsonObject o;
        o.insert(QStringLiteral("id"),          sys.id);
        o.insert(QStringLiteral("name"),         sys.name);
        o.insert(QStringLiteral("categoryId"),   sys.categoryId);
        o.insert(QStringLiteral("sliderIndex"),  sys.sliderIndex);
        o.insert(QStringLiteral("createdAt"),    sys.createdAt);
        o.insert(QStringLiteral("updatedAt"),    sys.updatedAt);
        if (!sys.content.isEmpty())
            o.insert(QStringLiteral("content"), sys.content);
        QJsonArray nodes;
        for (const Node& n : sys.nodes)
            nodes.append(nodeToJson(n));
        o.insert(QStringLiteral("nodes"), nodes);
        QJsonArray mentions;
        for (const Mention& m : sys.mentions)
            mentions.append(mentionToJson(m));
        o.insert(QStringLiteral("mentions"), mentions);
        systems.append(o);
    }
    QJsonObject root;
    root.insert(QStringLiteral("systems"), systems);

    QSaveFile f(path);
    if (!f.open(QIODevice::WriteOnly | QIODevice::Truncate)) return false;
    f.write(QJsonDocument(root).toJson(QJsonDocument::Indented));
    return f.commit();
}

// ── Static lookup ─────────────────────────────────────────────────────────────

const QList<ConstrutorStore::Category>& ConstrutorStore::categories()
{
    static const QList<Category> cats = buildCategories();
    return cats;
}

const ConstrutorStore::Category* ConstrutorStore::categoryById(const QString& id)
{
    for (const Category& c : categories())
        if (c.id == id) return &c;
    return nullptr;
}

// ── Systems CRUD ──────────────────────────────────────────────────────────────

ConstrutorStore::System* ConstrutorStore::findSystem(const QString& id)
{
    for (System& s : m_systems)
        if (s.id == id) return &s;
    return nullptr;
}

const ConstrutorStore::System* ConstrutorStore::system(const QString& id) const
{
    for (const System& s : m_systems)
        if (s.id == id) return &s;
    return nullptr;
}

QString ConstrutorStore::addSystem(const QString& name, const QString& categoryId,
                                    int sliderIndex)
{
    System sys;
    sys.id          = QUuid::createUuid().toString(QUuid::WithoutBraces);
    sys.name        = name;
    sys.categoryId  = categoryId;
    sys.sliderIndex = sliderIndex;
    sys.createdAt   = QDateTime::currentMSecsSinceEpoch();
    sys.updatedAt   = sys.createdAt;
    m_systems.append(std::move(sys));
    save();
    emit changed();
    return m_systems.last().id;
}

bool ConstrutorStore::updateSystem(const QString& id, const QString& name, int sliderIndex)
{
    System* sys = findSystem(id);
    if (!sys) return false;
    sys->name        = name;
    sys->sliderIndex = sliderIndex;
    sys->updatedAt   = QDateTime::currentMSecsSinceEpoch();
    save();
    emit changed();
    return true;
}

bool ConstrutorStore::updateSystemContent(const QString& id, const QString& content)
{
    System* sys = findSystem(id);
    if (!sys || sys->content == content) return false;
    sys->content   = content;
    sys->updatedAt = QDateTime::currentMSecsSinceEpoch();
    save();
    emit changed();
    return true;
}

bool ConstrutorStore::removeSystem(const QString& id)
{
    const int before = m_systems.size();
    m_systems.erase(std::remove_if(m_systems.begin(), m_systems.end(),
                                   [&](const System& s) { return s.id == id; }),
                    m_systems.end());
    if (m_systems.size() == before) return false;
    save();
    emit changed();
    return true;
}

// ── Nodes CRUD ────────────────────────────────────────────────────────────────

ConstrutorStore::Node* ConstrutorStore::findNode(QList<Node>& nodes, const QString& id)
{
    for (Node& n : nodes) {
        if (n.id == id) return &n;
        Node* c = findNode(n.children, id);
        if (c) return c;
    }
    return nullptr;
}

bool ConstrutorStore::removeNodeRecursive(QList<Node>& nodes, const QString& id)
{
    for (int i = 0; i < nodes.size(); ++i) {
        if (nodes[i].id == id) {
            nodes.removeAt(i);
            return true;
        }
        if (removeNodeRecursive(nodes[i].children, id)) return true;
    }
    return false;
}

QString ConstrutorStore::addNode(const QString& systemId, const QString& parentNodeId,
                                  NodeType type, const QString& name)
{
    System* sys = findSystem(systemId);
    if (!sys) return {};

    Node newNode;
    newNode.id        = QUuid::createUuid().toString(QUuid::WithoutBraces);
    newNode.name      = name;
    newNode.type      = type;
    newNode.updatedAt = QDateTime::currentMSecsSinceEpoch();

    if (parentNodeId.isEmpty()) {
        sys->nodes.append(newNode);
    } else {
        Node* parent = findNode(sys->nodes, parentNodeId);
        if (!parent) return {};
        parent->children.append(newNode);
    }

    save();
    emit changed();
    return newNode.id;
}

bool ConstrutorStore::updateNode(const QString& systemId, const QString& nodeId,
                                  const QString& name, const QString& content)
{
    System* sys = findSystem(systemId);
    if (!sys) return false;
    Node* node = findNode(sys->nodes, nodeId);
    if (!node) return false;
    node->name      = name;
    node->content   = content;
    node->updatedAt = QDateTime::currentMSecsSinceEpoch();
    save();
    emit changed();
    return true;
}

bool ConstrutorStore::removeNode(const QString& systemId, const QString& nodeId)
{
    System* sys = findSystem(systemId);
    if (!sys) return false;
    if (!removeNodeRecursive(sys->nodes, nodeId)) return false;
    save();
    emit changed();
    return true;
}

// ── Mentions CRUD ─────────────────────────────────────────────────────────────

QString ConstrutorStore::addMention(const QString& systemId, const Mention& mention)
{
    System* sys = findSystem(systemId);
    if (!sys) return {};

    Mention m = mention;
    m.id        = QUuid::createUuid().toString(QUuid::WithoutBraces);
    m.createdAt = QDateTime::currentMSecsSinceEpoch();
    sys->mentions.append(std::move(m));

    save();
    emit changed();
    return sys->mentions.last().id;
}

bool ConstrutorStore::removeMention(const QString& systemId, const QString& mentionId)
{
    System* sys = findSystem(systemId);
    if (!sys) return false;
    const int before = sys->mentions.size();
    sys->mentions.erase(std::remove_if(sys->mentions.begin(), sys->mentions.end(),
                                        [&](const Mention& m) { return m.id == mentionId; }),
                         sys->mentions.end());
    if (sys->mentions.size() == before) return false;
    save();
    emit changed();
    return true;
}
